class Piece:
    def __init__(self, color):
        self.color = color
        self.king = False

    def make_king(self):
        self.king = True


class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.init_board()

    def init_board(self):
        # Initialize the board with pieces
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('red')
        for row in range(5, 8):
            for col in range(row % 2, 8, 2):
                self.board[row][col] = Piece('black')

    def get_piece(self, position):
        return self.board[position[0]][position[1]]

    def move_piece(self, start, end):
        piece = self.get_piece(start)
        self.board[start[0]][start[1]] = None
        self.board[end[0]][end[1]] = piece
        if end[0] == 0 and piece.color == 'red' or end[0] == 7 and piece.color == 'black':
            piece.make_king()


class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'red'

    def run(self):
        while True:
            self.print_board()
            start, end = input(f"Player {self.current_player}, enter your move (e.g., a1-c3): ").split('-')
            start = (int(start[1]) - 1, ord(start[0].lower()) - 97)
